<h2>Projektai</h2><table><tr><th>ID</th><th>Klientas</th><th>Pavadinimas</th><th>Kategorija</th><th></th></tr><?php foreach($projects as $p): ?><tr><td><?= (int)$p['id'] ?></td><td><?= e($p['client_name']) ?></td><td><?= e($p['title']) ?></td><td><?= e($p['category_name']) ?></td><td><a href="<?= url('project.view') ?>&id=<?= (int)$p['id'] ?>">Open</a></td></tr><?php endforeach; ?></table>
<h2>Email logai</h2><table><tr><th>Email</th><th>Subject</th><th>Status</th><th>Date</th></tr><?php foreach($logs as $l): ?><tr><td><?= e($l['recipient_email']) ?></td><td><?= e($l['subject']) ?></td><td><?= e($l['status']) ?></td><td><?= e($l['created_at']) ?></td></tr><?php endforeach; ?></table>
<?php if(!empty($payments)): ?><h2>Payments</h2><table><tr><th>ID</th><th>User</th><th>Type</th><th>Amount</th><th>Status</th><th></th></tr><?php foreach($payments as $p): ?><tr><td><?= (int)$p['id'] ?></td><td><?= (int)$p['user_id'] ?></td><td><?= e($p['type']) ?></td><td><?= e((string)$p['amount']) ?> <?= e($p['currency']) ?></td><td><?= e($p['status']) ?></td><td><?php if(current_user()['role']==='admin'): ?><form method="post" action="<?= url('payments') ?>"><?= csrf_field() ?><input type="hidden" name="id" value="<?= (int)$p['id'] ?>"><select name="status"><option>pending</option><option>paid</option><option>failed</option><option>refunded</option></select><input name="provider_ref" placeholder="ref"><button>Update</button></form><?php endif; ?></td></tr><?php endforeach; ?></table><?php endif; ?>
